import sys
n = int(sys.stdin.read().split()[0])
count = 0
def place(row, cols, d1, d2):
    global count
    if row == n:
        count += 1; return
    for c in range(n):
        if cols & (1 << c) or d1 & (1 << (row + c)) or d2 & (1 << (row - c + n)):
            continue
        place(row + 1, cols | (1 << c), d1 | (1 << (row + c)), d2 | (1 << (row - c + n)))
place(0, 0, 0, 0)
print(count)

